function [imgExst,bgExst,bgName] = fImgListV01(imgDir,nmbSht,diagName) %% help for fImgListV01%% Returns a list of image exist logic for specified diagnostics% % imgExst = fImgListV01(imgDir,nmbSht,diagName) %% Input% imgDir: directory to check image% nmbSht: number of shots from logfile% diagName: diagnostic name such as 'StagingMagnetCam2'%% Output% imgExst: logic of image exist% bgExst: logic of bg image exist% Written by Kei Nakamura% 2012/4/26, Thursday.% Ver.1 Created. Succeeded from fDutchShtLstV01.m%%% main bodyname = ['/*_',diagName,'_*.png'];    % general name for imageimgLst = dir([imgDir,name]);         % image list[nmbImg,dlt] = size(imgLst);   % number of imagesimgExst = zeros(nmbSht,1);        % array for shot existfor jj=1:nmbImg    name = imgLst(jj).name;    prt = fGetPartStrV03(name,'_','&');    prt = fGetPartStrV03(prt,'_','.'); % since there are two _    shotNmb = str2num(prt);    if shotNmb>0        imgExst(shotNmb) = 1;      % make logic 1    else        bgExst = 1;        bgName = name;    endend
